  hash_t hash = CalculateHash(val);

  // Extract the register index from the first n_bits bits
  uint32_t register_idx = hash & ((1U << n_bits_) - 1);  // Lower n_bits bits

  // Get the remaining bits (shift out the first n_bits)
  hash_t remaining_bits = hash >> n_bits_;

  // Count leading zeros + 1 in the remaining bits
  uint64_t leading_zero_count = 0;
  if (remaining_bits == 0) {
    leading_zero_count = 65;  // All zeros in remaining bits
  } else {
    // Count leading zeros in 64-bit value
    leading_zero_count = __builtin_clzll(remaining_bits) + 1;
